Actionscript.script:
_root.挂机中 = false;
_root.gameworld[_root.控制目标].状态改变("空手站立");
_root.gameworld[_parent.挂机项目].gotoAndStop("准备挂机");
if(_parent.类别 == "加技能点")
{
   _parent.训练结束加技能点(_parent.将增加技能点);
   mytext.text = "你已完成了训练，将获得 " + _parent.将增加技能点 + " 点技能点。";
}
else if(_parent.类别 == "加经验")
{
   _parent.训练结束加经验值(_parent.将增加经验值);
   mytext.text = "你已完成了训练，将获得 " + _parent.将增加经验值 + " 点经验。";
}
